import { useState } from 'react';
import './Home.css'
function Home (){
    const [title,setTitle] = useState('')
    return(
        <div id='Home'>Home
            <input 
            type='text'
            placeholder='enter title here...'
            value={title}
            onChange={(e)=>setTitle(e.target.value)}
            />
        </div>
    )
}
export default Home;
